package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.exception.RegulException;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.enumtypes.CstEenheid;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.jpa.gl.ConstantPK;
import be.schaubroeck.lpb.tools.jpa.gl.ConstantPO;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.HashMultimap;
import com.google.common.collect.SetMultimap;
import lombok.AllArgsConstructor;
import lombok.Value;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

@Slf4j
@AllArgsConstructor
public class OverrideConstantManager implements ConstantManager {

    private final ConstantManager constantManager;
    private final SetMultimap<Integer, ConstantOverride> codeToOverrideMap = HashMultimap.create();

    public OverrideConstantManager(Admin admin, ConstantService constantService) {
        constantManager = new ConstantManagerImp(admin, constantService);
    }

    public void overrideConstant(LocalDateInterval periode, int code, Integer integer) {
        codeToOverrideMap.put(code, new ConstantOverride(periode, code, integer));
    }

    public void overrideConstant(LocalDateInterval periode, int code, Money bedrag) {
        codeToOverrideMap.put(code, new ConstantOverride(periode, code, bedrag));
    }

    public void overrideConstant(LocalDateInterval periode, int code, BigDecimal pctFactor) {
        codeToOverrideMap.put(code, new ConstantOverride(periode, code, pctFactor));
    }

    public void overrideConstant(LocalDateInterval periode, int code, LocalDate datum) {
        codeToOverrideMap.put(code, new ConstantOverride(periode, code, datum));
    }

    private Constant findOverride(Integer code, LocalDate datum) {
        return codeToOverrideMap.get(code).stream().filter(x -> x.contains(datum)).map(ConstantOverride::createConstant).findFirst().orElse(null);
    }

    @Override
    public Constant getActualConstant(Integer code, LocalDate rekenDatum, LocalDate selectieDatum, Boolean isAchterstal, boolean safe) {
        LocalDate datum = isAchterstal ? rekenDatum : selectieDatum;
        Constant constant = findOverride(code, datum);
        if (constant == null) {
            constant = constantManager.getActualConstant(code, rekenDatum, selectieDatum, isAchterstal, safe);
        }
        if (!safe) {
            checkConstanteGevonden(constant, code, datum);
        }
        return constant;
    }

    @Override
    public Constant getByCodeDatum(Integer code, LocalDate datum, boolean safe) {
        Constant constant = findOverride(code, datum);
        if (constant == null) {
            constant = constantManager.getByCodeDatum(code, datum, safe);
        }
        if (!safe) {
            checkConstanteGevonden(constant, code, datum);
        }
        return constant;
    }

    @Value
    private static class ConstantOverride {
        LocalDateInterval periode;
        Integer code;
        Integer integer;
        Money money;
        BigDecimal pctFactor;
        CstEenheid eenheid;
        LocalDate datum;

        public ConstantOverride(LocalDateInterval periode, Integer code, Integer integer) {
            this.periode = periode;
            this.code = code;
            this.integer = integer;
            this.money = null;
            this.pctFactor = null;
            this.datum = null;
            this.eenheid = CstEenheid.INTEGER;
        }

        public ConstantOverride(LocalDateInterval periode, Integer code, Money money) {
            this.periode = periode;
            this.code = code;
            this.integer = null;
            this.money = money;
            this.pctFactor = null;
            this.datum = null;
            this.eenheid = CstEenheid.MONEY;
        }

        public ConstantOverride(LocalDateInterval periode, Integer code, BigDecimal pctFactor) {
            this.periode = periode;
            this.code = code;
            this.integer = null;
            this.pctFactor = pctFactor;
            this.money = null;
            this.datum = null;
            this.eenheid = CstEenheid.PCTFACTOR;
        }

        public ConstantOverride(LocalDateInterval periode, Integer code, LocalDate datum) {
            this.periode = periode;
            this.code = code;
            this.integer = null;
            this.pctFactor = null;
            this.money = null;
            this.datum = datum;
            this.eenheid = CstEenheid.DATUM;
        }

        public Constant createConstant() {
            Constant constant = new ConstantPO();
            constant.setId(new ConstantPK());
            constant.setBeginDatum(periode.getStart());
            constant.setEindDatum(periode.getEnd());
            switch (eenheid) {
                case MONEY:
                    constant.setMoney(money);
                    break;
                case PCTFACTOR:
                    constant.setProcentFactor(pctFactor);
                    break;
                case DATUM:
                    constant.setDatum(datum);
                    break;
                case INTEGER:
                    constant.setInteger(integer);
                default:
                    //do nothing
            }
            return constant;
        }

        public boolean contains(LocalDate datum) {
            return periode.contains(datum);
        }

    }

    private static void checkConstanteGevonden(Constant constant, Integer code) {
        if (constant == null) {
            log.error("Constante met code {} niet gevonden.", code);
            throw new RegulException(null, null, Regulkode.CONSTANTE_NIET_GEVONDEN, null, null);
        }
    }

    private static void checkConstanteGevonden(Constant constant, Integer code, LocalDate date) {
        if (constant == null) {
            log.error("Constante met code {} en datum {} niet gevonden.", code, date);
            throw new RegulException(null, null, Regulkode.CONSTANTE_NIET_GEVONDEN, null, null);
        }
    }


    //Onderstaande methodes zijn default parameter methodes.

    @Override
    public Constant getActualConstant(Konstanten constant, RekenTijd rekenTijd) {
        return this.getActualConstant(constant.getCode(), rekenTijd.rekenDatum, rekenTijd.eindDatum, rekenTijd.isAchterstal, false);
    }

    @Override
    public Constant getActualConstant(Konstanten constant, RekenTijd rekenTijd, LocalDate selectieDatum) {
        return this.getActualConstant(constant.getCode(), rekenTijd.rekenDatum, selectieDatum, rekenTijd.isAchterstal, false);
    }

    @Override
    public Constant getActualConstant(Integer code, RekenTijd rekenTijd) {
        return this.getActualConstant(code, rekenTijd.rekenDatum, rekenTijd.eindDatum, rekenTijd.isAchterstal, false);
    }

    @Override
    public Constant getActualConstantSafe(Integer code, RekenTijd rekenTijd) {
        return this.getActualConstant(code, rekenTijd.rekenDatum, rekenTijd.eindDatum, rekenTijd.isAchterstal, true);
    }

    @Override
    public Constant getByCodeDatum(Integer code, LocalDate datum) {
        return this.getByCodeDatum(code, datum, false);
    }

    @Override
    public Constant getByCodeDatumSafe(Integer code, LocalDate datum) {
        return this.getByCodeDatum(code, datum, true);
    }

    @Override
    public Constant getByCodeDatum(Konstanten constant, LocalDate datum) {
        return this.getByCodeDatum(constant.getCode(), datum, false);
    }

}
